"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const chapters=[['Context','Set the scope before reading.'],['Evidence','Compare the attributable proof.'],['Outcome','Record the chosen next step.']];
export default function OutlinePulseRail(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <nav aria-label="Reading outline" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">reading outline</p><div className="relative mt-4 grid gap-2 border-l-2 border-[#ececee] pl-5"><motion.i aria-hidden className="absolute -left-[7px] top-4 h-3 w-3 rounded-full bg-[#fb6a4a]" animate={{y:active*54}} transition={reduced?{duration:0}:{type:"spring",stiffness:330,damping:26}}/>{chapters.map((chapter,index)=><button key={chapter[0]} type="button" aria-current={active===index?'step':undefined} onClick={()=>setActive(index)} className="min-h-11 rounded-xl px-2 text-left outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"><span className="block text-sm font-black text-[#111]">{chapter[0]}</span><span className="text-xs text-[#4a4a4f]">{active===index?chapter[1]:'Open chapter'}</span></button>)}</div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Reading {chapters[active][0]}.</p></nav>}
